INSERT INTO `jinengxuqiu` (`addtime`, `xuqiubianhao`, `xuqiubiaoti`, `jinengfenlei`, `fengmian`, `fabushijian`, `xuqiufeiyong`, `xuqiumiaoshu`, `xuqiuxiangqing`, `yonghuzhanghao`, `yonghuxingming`, `shoujihao`, `xinyuzhishu`, `sfsh`, `shhf`, `thumbsupnum`, `crazilynum`, `clicktime`, `clicknum`, `discussnum`, `totalscore`, `storeupnum`) VALUES
('2026-04-18 09:30:00','XQ20260425001','短视频制作教学','工具','upload/jinengxuqiu_短视频剪辑1.jpg,upload/jinengxuqiu_短视频剪辑2.jpg,upload/jinengxuqiu_短视频剪辑3.jpg','2026-04-18',85,'熟练使用剪映和PR进行短视频创作，擅长vlog拍摄与后期剪辑','<p>拥有两年短视频创作经验，熟悉抖音、B站等平台的内容风格。可以教授：</p><ul><li>手机拍摄技巧和运镜方法</li><li>剪映/PR基础操作和进阶技巧</li><li>转场特效、字幕动画制作</li><li>调色和音频处理</li></ul><p>适合零基础想入门短视频的同学，也欢迎有一定基础想提升的朋友。</p>','wanghao','王浩','13290125678','86','是','',3,0,'2026-04-25 14:30:00',22,2,4,2),
('2026-04-20 14:00:00','XQ20260425002','英语口语陪练','语言','upload/jinengxuqiu_配音技巧教学1.jpg,upload/jinengxuqiu_配音技巧教学2.jpg,upload/jinengxuqiu_配音技巧教学3.jpg','2026-04-20',60,'英语六级580分，擅长日常口语和商务英语会话练习','<p>本人英语六级580分，有丰富的英语交流经验：</p><ul><li>日常英语会话训练</li><li>四六级口语考试备考指导</li><li>英文面试模拟练习</li><li>英语发音纠正和听力提升方法</li></ul><p>每周可安排2-3次线上语音练习，每次30-45分钟。希望用英语技能换取设计或编程方面的技能。</p>','wanghao','王浩','13290125678','86','是','',5,0,'2026-04-26 10:00:00',35,3,5,3);

SET NAMES utf8mb4;

INSERT INTO `forum` (`addtime`, `typename`, `title`, `content`, `parentid`, `username`, `avatarurl`, `isdone`, `istop`, `cover`, `isanon`, `delflag`, `sfsh`, `shhf`, `userid`) VALUES
('2026-04-16 20:30:00','工具','分享｜用剪映做出电影感vlog的技巧','最近研究了一下怎么用剪映做出有电影感的vlog，分享几个技巧：1. 使用2.35:1的宽屏比例裁剪画面，瞬间提升电影感；2. 调色用低饱和度+青橙色调，模拟胶片风格；3. 加入合适的背景音乐，推荐轻音乐或氛围感音乐；4. 转场不要太花哨，简单的淡入淡出最高级；5. 字幕用无衬线字体，字号不要太大。附上我用这些技巧剪的一支校园vlog，欢迎交流讨论！',0,'王浩','upload/yonghu_touxiang8.jpg','开放',0,'upload/forum_video_edit.jpg',0,0,'是','',18),
('2026-04-19 18:20:00','艺术','吉他入门一个月心得｜零基础如何快速上手','学吉他一个月了，从完全不会到能弹唱《晴天》，分享一下我的学习过程：第1周认识吉他各部位，学会调音，练习C、Am、G三个基础和弦；第2周练习和弦转换，左手按弦要到位，右手节奏要稳；第3周学会扫弦和分解和弦，开始尝试简单曲目；第4周完整弹唱第一首歌。最重要的经验：每天至少练习30分钟，坚持比技巧更重要！手指起茧是正常的，过了这个阶段就好了。有一起学吉他的同学欢迎互相交流！',0,'王浩','upload/yonghu_touxiang8.jpg','开放',0,'upload/forum_guitar.jpg',0,0,'是','',18),
('2026-04-21 15:45:00','学习','大学生如何高效利用碎片时间学习新技能','作为一个同时在学吉他、英语和视频剪辑的人，分享一下我的碎片时间管理方法：通勤时间听英语播客或背单词App；课间休息看一个短视频教程的片段；午休前练习吉他和弦转换；睡前复习当天学到的知识点。关键是要把大目标拆解成小任务，每天进步一点点。另外推荐几个好用的学习App：Anki（间隔重复记忆）、Forest（专注计时）、Notion（知识整理）。大家有什么好的学习方法也欢迎分享！',0,'王浩','upload/yonghu_touxiang8.jpg','开放',0,'upload/forum_calligraphy.jpg',0,0,'是','',18);

SET NAMES utf8mb4;

INSERT INTO `forum` (`addtime`, `typename`, `title`, `content`, `parentid`, `username`, `avatarurl`, `isdone`, `istop`, `cover`, `isanon`, `delflag`, `sfsh`, `shhf`, `userid`) VALUES
('2026-04-15 21:00:00','编程','','推荐《Python Crash Course》，这本书非常适合有其他语言基础的同学入门。学完基础语法后建议往数据分析方向走，pandas和matplotlib组合很实用，做课程作业和毕业设计都用得上。',1,'王浩','upload/yonghu_touxiang8.jpg','开放',0,NULL,0,0,'是','',18),
('2026-04-17 12:30:00','生活','','手机摄影技巧补充：开启网格线辅助构图，善用人像模式拍人物，逆光拍摄时点击暗部对焦可以拍出剪影效果。另外推荐VSCO这个App做后期，滤镜质感比较高级。',2,'王浩','upload/yonghu_touxiang8.jpg','开放',0,NULL,0,0,'是','',18),
('2026-04-23 19:15:00','艺术','','作为吉他社的一员，非常欢迎零基础的同学加入！我就是在社里从零开始学的，学长们都很有耐心。建议新同学先从尤克里里入手也行，四根弦比六根弦容易上手。',8,'王浩','upload/yonghu_touxiang8.jpg','开放',0,NULL,0,0,'是','',18);

