INSERT INTO `messages` (`addtime`, `userid`, `username`, `avatarurl`, `content`, `cpicture`, `reply`, `rpicture`) VALUES
('2026-04-13 20:00:00',18,'王浩','upload/yonghu_touxiang8.jpg','你好，我刚注册了账号，想问一下怎么发布技能需求？需要审核多长时间？',NULL,'欢迎加入平台！点击技能需求页面的发布按钮即可，审核一般24小时内完成。如有问题可随时留言。',NULL),
('2026-04-18 15:30:00',18,'王浩','upload/yonghu_touxiang8.jpg','建议增加一个技能交换日历功能，方便双方约定交换时间，避免时间冲突。另外希望能支持视频消息功能。',NULL,'感谢您的宝贵建议！日历功能已经列入开发计划，预计下个版本会上线。视频消息功能也在规划中。',NULL),
('2026-04-24 21:00:00',18,'王浩','upload/yonghu_touxiang8.jpg','平台使用体验很好，推荐算法推荐的内容很精准。希望以后能增加视频教学直播功能，实现实时互动教学，这样技能交换会更高效。',NULL,NULL,NULL);

SET NAMES utf8mb4;

INSERT INTO `chat` (`addtime`, `userid`, `adminid`, `ask`, `reply`, `isreply`, `isread`, `uname`, `uimage`, `type`) VALUES
('2026-04-15 09:00:00',18,1,'请问怎么提升自己的信誉指数？','您的信誉指数可以通过以下方式提升：1. 积极完成技能交换，每次完成交换可获得积分；2. 获得交换对象的好评会加分；3. 在社区发布有价值的帖子并获得点赞也有加成；4. 保持良好的交易记录，避免违规行为。目前您的信誉指数为86，继续保持良好的交易习惯即可稳步提升。',1,1,'王浩','upload/yonghu_touxiang8.jpg',1),
('2026-04-19 14:00:00',18,1,'我想学Python编程，平台上有推荐的学习路线吗？','推荐您从以下步骤开始学习Python：1. 先查看学习资料中的"Python自动化脚本编写"教程，内容由浅入深；2. 在技能需求板块搜索Python相关需求，目前有"Python编程入门"正在招收学员；3. 社区论坛中有Python学习讨论帖，可以参与交流获取经验。建议同时关注"软件研发"分类的学习资料，内容非常丰富实用。',1,1,'王浩','upload/yonghu_touxiang8.jpg',1),
('2026-04-23 10:30:00',18,1,'如何查看我发布的技能需求的浏览数据？','您可以在个人中心查看已发布的技能需求列表，每个需求卡片上会显示浏览量、收藏数、评论数等数据。点击进入详情页还可以查看更详细的互动信息。如果想了解哪些用户收藏了您的需求，可以在后台管理中查看。',1,1,'王浩','upload/yonghu_touxiang8.jpg',1);

